// MULTICAL 603 parser voor default datagram xx-yy-300
// Verwacht:
// - Modbus read startadres: 0
// - Quantity: 56
// - FC: eerst 3 testen, indien geen goede data -> 4 testen
//
// Mapping volgens Kamstrup default datagram:
// reg 1  = Flow V1 actual
// reg 3  = Flow V2 actual
// reg 7  = t1 actual
// reg 9  = t2 actual
// reg 11 = t3 actual
// reg 13 = t4 actual
// reg 21 = Heat energy E1
// reg 23 = Heat energy E2
// reg 53 = Volume V1
// reg 55 = Volume V2

const INVALID_FLOAT_HEX = 0x4F800000;

const buffer = new ArrayBuffer(4);
const intView = new Uint32Array(buffer);
const floatView = new Float32Array(buffer);

// NORMALE LEESVOLGORDE
// Gebruik deze eerst
function regsToFloat(indexHigh, indexLow) {
    const combined = ((msg.payload[indexHigh] << 16) | msg.payload[indexLow]) >>> 0;

    // Invalid value volgens Kamstrup
    if (combined === INVALID_FLOAT_HEX) {
        return null;
    }

    intView[0] = combined;
    return Number(floatView[0].toFixed(3));
}

/*
// ALTERNATIEVE LEESVOLGORDE (WORD SWAP)
// Haal deze uit commentaar en zet de functie hierboven in commentaar
// als je rare waarden krijgt zoals:
// - gigantische getallen
// - negatieve temperaturen die niet kunnen
// - 0.000 terwijl display duidelijke waarde toont
function regsToFloat(indexHigh, indexLow) {
    const combined = ((msg.payload[indexLow] << 16) | msg.payload[indexHigh]) >>> 0;

    if (combined === INVALID_FLOAT_HEX) {
        return null;
    }

    intView[0] = combined;
    return Number(floatView[0].toFixed(3));
}
*/

if (!Array.isArray(msg.payload)) {
    node.error("msg.payload is geen array", msg);
    return null;
}

if (msg.payload.length < 56) {
    node.error("Payload te klein voor MULTICAL 603 parser", msg);
    return null;
}

let data = {};

// Flows
data["flow_v1_actual"] = regsToFloat(0, 1);    // reg 1-2
data["flow_v2_actual"] = regsToFloat(2, 3);    // reg 3-4

// Temperaturen
data["temperature_t1"] = regsToFloat(6, 7);    // reg 7-8
data["temperature_t2"] = regsToFloat(8, 9);    // reg 9-10
data["temperature_t3"] = regsToFloat(10, 11);  // reg 11-12
data["temperature_t4"] = regsToFloat(12, 13);  // reg 13-14

// Energie
data["heat_e1"] = regsToFloat(20, 21);         // reg 21-22
data["heat_e2"] = regsToFloat(22, 23);         // reg 23-24

// Volumes
data["volume_v1"] = regsToFloat(52, 53);       // reg 53-54
data["volume_v2"] = regsToFloat(54, 55);       // reg 55-56

// Optioneel: null-waarden verwijderen
for (const key of Object.keys(data)) {
    if (data[key] === null) {
        delete data[key];
    }
}

msg.payload = data;
return msg;

// Haal de globale MID variabele op
let mid = global.get("mid") || 0;

// Stel de constante Dev in
const Dev = "ASSET";

// Mapping naar interne datatype-ID's
const idMapping = {
    flow_v1_actual: 9660, //ok
    flow_v2_actual: 9661, // ok

    temperature_t1: 9701, // ok
    temperature_t2: 9702, // ok
    temperature_t3: 9703, // ok 
    temperature_t4: 9704, // ok

    heat_e1: 9600, // ok
    heat_e2: 9603, // ok 

    volume_v1: 9650, //ok
    volume_v2: 9651 // ok
};

// Maak mapping case-insensitive
const normalizedIdMapping = Object.create(null);
for (const [k, v] of Object.entries(idMapping)) {
    normalizedIdMapping[k.toLowerCase()] = v;
}

// Begin resultaat-object
let result = {
    MID: mid,
    D: [
        {
            Dev: Dev,
            ED: [],
            MD: []
        }
    ]
};

// Altijd timestamp zetten
result.D[0].TS = new Date().toISOString();

// Payload van parser
let payloadData = msg.payload;

if (!payloadData || typeof payloadData !== "object" || Array.isArray(payloadData)) {
    node.warn("msg.payload is geen geldig object voor de MULTICAL decoder");
    return null;
}

for (const [key, raw] of Object.entries(payloadData)) {
    const normalizedKey = key.toLowerCase();
    const id = normalizedIdMapping[normalizedKey];
    if (id === undefined) continue;

    if (raw === null || typeof raw === "object") {
        node.warn(`Overslaan ${key}: waarde is geen primitief (${typeof raw})`);
        continue;
    }

    const val = Number(raw);
    if (!Number.isFinite(val)) {
        node.warn(`Ongeldige numerieke waarde voor ${key}: "${raw}"`);
        continue;
    }

    result.D[0].MD.push({
        Id: id,
        Val: val
    });
}

// Alleen MID verhogen als er data is
if (result.D[0].MD.length > 0) {
    global.set("mid", mid + 1);
} else {
    node.warn("Geen geldige meetwaarden gevonden in decoder");
}

msg.payload = result;
return msg;

if (msg.error) {
  msg.failReason = msg.error;
  return [null, msg];
}

if (!Array.isArray(msg.payload)) {
  msg.failReason = `payload_not_array (${typeof msg.payload})`;
  return [null, msg];
}

if (msg.payload.length !== 56) {
  msg.failReason = `bad_length (${msg.payload.length})`;
  return [null, msg];
}

if (msg.payload.every(v => v === 0)) {
  msg.failReason = "all_zero_payload";
  return [null, msg];
}

return [msg, null];

// ===== Modbus FAIL -> ED event wrapper =====

// 1) MID
let mid = global.get("mid") || 0;

// 2) Device
// Vul je echte asset-id in of haal uit msg (als je die meegeeft op fail-pad)
const Dev =  "ASSET";

// 3) Event Id voor "modbus failure" (kies zelf een vrije ID)
const MODBUS_FAIL_EVENT_ID = 7199;

// 4) Reason bepalen (prioriteit: msg.failReason -> msg.error -> algemene fallback)
let reason = msg.failReason || msg.error || "MODBUS_FAIL";

// 5) Bouw extra context (unitId, queue length, topic, messageId)
const unitId = msg.unitId ?? msg.queueUnitId ?? (msg.queueLengthByUnitId?.unitId);
const qLen =
  msg.queueLengthByUnitId?.queueLength ??
  msg.queueLength ??
  undefined;

let details = [];
if (unitId !== undefined) details.push(`unitId=${unitId}`);
if (qLen !== undefined) details.push(`queueLen=${qLen}`);
if (msg.topic) details.push(`topic=${msg.topic}`);
if (msg.messageId) details.push(`messageId=${msg.messageId}`);

let val = String(reason);
if (details.length) val += ` | ${details.join(", ")}`;

// 6) Wrapper result
const result = {
  MID: mid,
  D: [
    {
      Dev: Dev,
      TS: new Date().toISOString(),
      ED: [
        {
          Id: MODBUS_FAIL_EVENT_ID,
          Val: val,   // <-- reden als tekst
          Sev: 2
        }
      ],
      MD: []
    }
  ]
};

// 7) MID ophogen (ik doe dit altijd voor fail-events)
global.set("mid", mid + 1);

// 8) Output
msg.payload = result;
msg.topic = "telemetry"; // als je dit verwacht downstream (optioneel)
return msg;

const DELAY_MS = 7500;
const MAX_RETRY = 6;

const Dev = "ASSET";          
const RETRY_WARN_EVENT_ID = 7198;          

let q = (msg.queque || "").toLowerCase();
let retry = global.get("retry") || 0;

function sendLater(out1, out2, out3) {
  setTimeout(() => node.send([out1, out2, out3]), DELAY_MS);
}

// ---- FAIL ----
if (q === "fail") {
  retry += 1;
  global.set("retry", retry);

  // retry < 5 => output 1 ("go")
  if (retry < MAX_RETRY) {
    const m1 = {
      ...msg,
      action: "go",
      retry
    };
    sendLater(m1, null, null);
    return;
  }

  // retry >= 5 => na 5 sec: reset + output 2 ("stop/failover")
  global.set("retry", 0);

  const m2 = {
    ...msg,
    action: "stop",
    retry: MAX_RETRY
  };

  sendLater(null, m2, null);
  return;
}

// ---- SUCCESS ----
if (q === "success") {
  const retriesUsed = retry; 

  // Case A: success met <=1 retry => gewoon output 2 na 5 sec, reset
  if (retriesUsed <= 1) {
    global.set("retry", 0);

    const m2 = {
      ...msg,
      action: "ok",
      retry: 0
    };

    sendLater(null, m2, null);
    return;
  }

  // Case B: success maar met >1 retries => output 2 én output 3, reset
  global.set("retry", 0);

  // Output 2: control/success message
  const m2 = {
    ...msg,
    action: "ok_but_retried",
    info: `success but retried ${retriesUsed} times`,
    retriesUsed,
    retry: 0
  };

  // Output 3: ED event payload (severity 2)
  const mid = global.get("mid") || 0;
  global.set("mid", mid + 1);

  const m3 = {
    topic: "telemetry",
    queque: "event",
    payload: {
      MID: mid,
      D: [
        {
          Dev,
          TS: new Date().toISOString(),
          ED: [
            {
              Id: RETRY_WARN_EVENT_ID,
              Val: `success but retried ${retriesUsed} times`,
              Sev: 2
            }
          ],
          MD: []
        }
      ]
    }
  };

  sendLater(null, m2, m3);
  return;
}

const m2 = {
  ...msg,
  action: "unknown_queque",
  retry
};
sendLater(null, m2, null);
return;
